import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import './SignUp.css';

function SignUp() {
    const [username, setUsername] = useState('');
    const [email, setEmail] = useState('');
    const [password, setPassword] = useState('');
    const navigate = useNavigate();

    const handleSignUp = () => {
        if (username && email && password) {
            const user = { id: Date.now(), username, email, password };
            const csvLine = `${user.id},${user.username},${user.email},${user.password}\n`;

            // Save the user to the users.csv file in the project directory
            const fs = require('fs');
            const path = require('path');
            const filePath = path.join(__dirname, 'users.csv');

            fs.appendFile(filePath, csvLine, (err) => {
                if (err) {
                    console.error('Error writing to file', err);
                } else {
                    console.log('User added to CSV file');
                }
            });

            navigate('/signin');
        } else {
            alert('Please fill in all fields.');
        }
    };

    return (
        <div className="signup-container">
            <h2>Sign Up</h2>
            <input
                type="text"
                placeholder="Username"
                value={username}
                onChange={(e) => setUsername(e.target.value)}
            />
            <input
                type="email"
                placeholder="Email"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
            />
            <input
                type="password"
                placeholder="Password"
                value={password}
                onChange={(e) => setPassword(e.target.value)}
            />
            <button onClick={handleSignUp}>Sign Up</button>
        </div>
    );
}

export default SignUp;
